#include <bits/stdc++.h>
using namespace std;
const int N=3005;
struct edge
{
    int id,nxt,w;
} e[2*N];
int n,m,tot,head[N],siz[N],dp[N][N];
void add(int u,int v,int w)
{
    e[++tot].id=v;
    e[tot].nxt=head[u];
    e[tot].w=w;
    head[u]=tot;
}
void dfs(int num,int fa)
{
    if(num>=n-m+1)
    {
        siz[num]=1;
        return ;
    }
    for(int i=head[num];i;i=e[i].nxt)
    {
        int x=e[i].id;
        if(x==fa) continue;
        dfs(x,num);
        siz[num]+=siz[x];
        for(int j=siz[num];j>-1;j--)
        {
            for(int k=0;k<=siz[x]&&k<=j;k++)
            {
                dp[num][j]=max(dp[num][j],dp[num][j-k]+dp[x][k]-e[i].w);
            }
        }
    }
}
int main()
{
    cin>>n>>m;
    int num,v,w;
    for(int i=1;i<=n-m;i++)
    {
        cin>>num;
        for(int j=1;j<=num;j++)
        {
            cin>>v>>w;
            add(i,v,w);
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            dp[i][j]=-1e9;
        }
    }
    for(int i=n-m+1;i<=n;i++)
    {
        cin>>dp[i][1];
    }
    dfs(1,0);
    for(int i=siz[1];i>=0;i--)
    {
        if(dp[1][i]>=0)
        {
            cout<<i;
            return 0;
        }
    }
    return 0;
}
